   427→		Summary: "Set a location list",
   428→		Synopsis: "[options] <uri> <priority> <id>" +
   429→			" <json-locations>\n" +
   430→			"  priority: info|warning|error|critical\n" +
   431→			"  json-locations: " +
   432→			`[{"from":{"x":N,"y":N},` +
   433→			`"to":{"x":N,"y":N},` +
   434→			`"message":"..."},...]`,
   435→		Options: *c.fs,
   436→	}
