func TestJSON(t *testing.T) {
	type testCase struct {
		name    string
		setup   func(*testEnv)
		args    []string
		wantErr bool
		raw     bool // iterator output, no success field
	}
	tests := []testCase{
		{
			name: "datadir/ok",
			args: []string{
				"datadir", "-F", "json",
			},
		},
		{
			name: "uri/ok",
			args: []string{
				"uri", "-F", "json",
				"/tmp/test.txt",
			},
		},
		{
			name: "open/ok",
			args: []string{
				"open", "-F", "json",
				"file:///tmp/test.txt",
			},
		},
		{
			name: "notify/ok",
			args: []string{
				"notify", "-F", "json",
				"info", "hello",
			},
		},
		{
