		{
			name:   "t",
			format: "table",
			check: func(t *testing.T, out string) {
				require.Contains(t, out, "DATA DIR")
			},
		},
		{
			name:   "g",
			format: "{{.DataDir}}",
			check: func(t *testing.T, out string) {
