			out, err := env.run(tt.args...)
			require.NoError(t, err)
			out = strings.TrimSpace(out)
			var m map[string]any
			require.NoError(t,
				json.Unmarshal(
					[]byte(out), &m,
				),
				"invalid JSON: %s", out,
			)
			if tt.wantErr {
				require.Equal(t,
					false, m["success"],
				)
				errMsg, ok :=
					m["error"].(string)
				require.True(t, ok,
					"missing error: %s", out,
